Author: John Wilger <john@johnwilger.com>
Date:   Sun Feb 8 14:25:24 2026 -0800

    Add missing CSS styles for nav-logout, todo-add errors, auth-form actions

    Addresses CSS gaps flagged during polish review:

    - .nav-logout / .nav-logout__button: position logout form right-aligned
      in header nav, style button as muted text link (not primary button)
    - .todo-add__group: spacing for the add-todo label+input group
    - .todo-add__submit: fix class mismatch (was .todo-add__button in CSS
      but .todo-add__submit in template)
    - .todo-add__error: danger color, small font, :empty collapse
    - .auth-form__message:empty: collapse empty error containers to remove gap
    - .auth-form__actions: flexbox row for save/cancel button pair
    - .auth-form__cancel: secondary text-link styling for cancel action

    Co-Authored-By: Claude Opus 4.6 (1M context) <noreply@anthropic.com>

diff --git a/static/css/main.css b/static/css/main.css
index 82513aa..043a645 100644
--- a/static/css/main.css
+++ b/static/css/main.css
@@ -592,6 +592,11 @@
     margin-block-end: var(--space-lg);
   }

+  /* Collapse empty message containers so they don't leave a gap */
+  .auth-form__message:empty {
+    display: none;
+  }
+
   .auth-form__message--error {
     background-color: var(--color-danger-light);
     color: var(--color-danger);
@@ -601,6 +606,23 @@
     inline-size: 100%;
   }

+  /* Actions row (save + cancel) for edit forms */
+  .auth-form__actions {
+    display: flex;
+    align-items: center;
+    gap: var(--space-md);
+  }
+
+  /* Cancel link styled as secondary text action */
+  .auth-form__cancel {
+    font-size: var(--font-size-sm);
+    color: var(--color-fg-muted);
+  }
+
+  .auth-form__cancel:hover {
+    color: var(--color-fg);
+  }
+
   .auth-form__footer {
     margin-block-start: var(--space-lg);
     text-align: center;
@@ -652,6 +674,30 @@
     text-decoration: underline;
   }

+  /* ---- Nav Logout ----
+   * Logout form positioned to the right side of the header nav.
+   * The button is styled as a text link, not a primary button. */
+  .nav-logout {
+    margin-inline-start: auto;
+  }
+
+  .nav-logout__button {
+    background: none;
+    border: none;
+    color: var(--color-fg-muted);
+    font-size: var(--font-size-sm);
+    font-weight: var(--font-normal);
+    padding: 0;
+    border-radius: 0;
+    cursor: pointer;
+  }
+
+  .nav-logout__button:hover {
+    background: none;
+    color: var(--color-fg);
+    text-decoration: underline;
+  }
+
   /* ---- Todo Add Form ----
    * Prominent input at top of todo list for adding new items.
    * Label above, input + button row below. */
@@ -659,6 +705,10 @@
     margin-block: var(--space-lg);
   }

+  .todo-add__group {
+    margin-block-end: var(--space-xs);
+  }
+
   .todo-add__label {
     display: block;
     font-size: var(--font-size-sm);
@@ -675,10 +725,20 @@
     flex: 1;
   }

-  .todo-add__button {
+  .todo-add__submit {
     flex-shrink: 0;
   }

+  /* Error text for the add-todo form (always in DOM for aria-describedby) */
+  .todo-add__error {
+    color: var(--color-danger);
+    font-size: var(--font-size-sm);
+  }
+
+  .todo-add__error:empty {
+    display: none;
+  }
+
   /* ---- Todo List ----
    * Vertical list of todo items separated by borders.
    * Each item is a flex row: checkbox + label (title). */

